import React, {Component} from 'react';
// import ReactDOM from "react-dom";
import { FaHeartbeat } from 'react-icons/fa';
import '../../node_modules/react-linechart/dist/styles.css';
import firebase from './firebase';
import { VictoryLine, VictoryChart, VictoryTheme, VictoryAxis } from 'victory';

// import Push from 'push.js';

class HeartRate extends Component {
    constructor(){
        super();
        this.state = {
            bpm: 0,
            connect: false,
            items: []
        }
    }

    componentDidMount(){
        const info = firebase.database().ref('info');
        const ecg = firebase.database().ref('data/ecg');
        const bpm = firebase.database().ref('data/bpm')
        ecg.on('value', (snapshot) => {
            let items = snapshot.val();
            let newState = [];
            for (let item in items) {
                let date = new Date();
                newState.push({
                    key: item,
                    data: items[item],
                    time: date.getDate()
                });
            }

            this.setState({
                items: newState
            });
        });

        bpm.on('value', (snapshot) => {
            let item = snapshot.val();
            this.setState({
                bpm: item
            })
            if(!this.state.connect){
                this.setState({
                    bpm: 0
                })
            }
        })

        setInterval(()=>{
            info.on('value', (snapshot) => {
                let items = snapshot.val();
                this.setState({
                    connect: items.connect
                })
            })
        }, 60*1000);

    }

    render(){
        const {connect, items, bpm} = this.state;
        const {isOpen} = this.props;
        const data = [];

        items.map((item, i)=>{
            return data.push({x: i, y: item.data})
        });
        // let countPush = 0;
        // if(!connect && countPush <1) countPush = 1;
        // if(countPush>0){
        //     setTimeout(()=>{
        //         Push.create("Something goes wrong! ", {
        //             body: "Please check patient",
        //             vibrate: 200,
        //             requireInteraction: true,
        //             onClick: function () {
        //                 window.focus();
        //                 this.close();
        //             }
        //         });
        //         console.log("this")
        //     }, 5*60*1000)
        //     countPush = 0;
        // }

        return(
            <div className={isOpen ? "heart-monitor open" : "heart-monitor"}>
                <div className="bpm">
                    <FaHeartbeat className="heart"  />
                    {parseInt(bpm)}
                 </div>
                {connect ? "" : <p className="not-connect">Lose connection</p>}
                <VictoryChart
                    theme={VictoryTheme.material}
                    width={700}
                    height={320}
                >
                    <VictoryAxis style={{ axis: {stroke: "none"} }}
                                 tickFormat={() => ''}
                    />
                    <VictoryLine
                        style={{
                            data: { stroke: `${connect? "#2ecc71":"red"}` }
                        }}
                        data={data}
                    />
                </VictoryChart>
                <a className="download">Download</a>
            </div>
        );
    }
}

export default HeartRate;